INSERT INTO lessons (course_id, title, type, content, sort_order) VALUES
(1, 'Зачем уметь готовить', 'free', '
<h1>Зачем уметь готовить</h1>
<p>Честный ответ: не потому что надо, а потому что это самый дешёвый способ не сойти с ума в новой квартире. Доставка съедает полторы зарплаты в месяц и превращает любой вечер в ожидание курьера. Кухню — в склад одноразовых контейнеров.</p>
<p>Вам не нужно учиться готовить <strong>хорошо</strong>. Достаточно уметь сделать три-четыре базовых блюда, которые не вредят желудку и не требуют получасового ритуала. Пельмени — отличная точка старта: шесть минут, кастрюля, сметана.</p>
<p>В этом курсе мы пройдём путь от «где у плиты кнопка» до «а что если я сам слеплю пельмени в субботу». Без гастро-энциклопедий и телевизионных шеф-поваров.</p>
', 1),

(1, 'Как выбрать пельмени в магазине', 'free', '
<h1>Как выбрать пельмени в магазине</h1>
<p>Три параметра, на которые стоит смотреть. Всё остальное — упаковка и ужимки маркетолога.</p>
<p><strong>Тесто.</strong> Посмотрите через прозрачную плёнку упаковки: пельмени должны быть отдельными, не слипшимися в один ком. Если вся пачка стала единым белым кирпичом — их размораживали и замораживали снова. Вкуса там уже нет.</p>
<p><strong>Состав.</strong> На первом месте должно стоять мясо, а не «продукт мясосодержащий». Слова «свинина», «говядина», «баранина» — ваши друзья. «Соя» — нейтрально, но ниже по списку.</p>
<p><strong>Цена за килограмм, а не за упаковку.</strong> Пачка 800 грамм за 400 рублей и пачка 500 грамм за 280 — это разный продукт. Считайте рубли на кило, это дисциплинирует.</p>
', 2),

(1, 'Кипящая вода: наука без романтики', 'free', '
<h1>Как сварить пельмени и не склеить их в ком</h1>
<p>Главное правило: воды должно быть много. На 500 грамм пельменей — полная кастрюля, не меньше двух литров. В тесной кастрюле они слипаются между собой, в просторной — плавают как надо.</p>
<p>Сначала доводим воду до кипения. Не до небольшого пара, а до настоящего бурления пузырьков. Тогда солим (щедро, примерно столовая ложка) и кладём лаврушку, если есть настроение.</p>
<p>Пельмени высыпаем в кипящую воду и <strong>сразу</strong> аккуратно перемешиваем ложкой. Это самый важный момент — они тонут, прилипают ко дну, и их надо оторвать, пока не поздно.</p>
<p>Ждём, пока вода закипит снова. С этого момента отсчитываем 5–7 минут — зависит от размера. Когда пельмени всплыли и слегка надулись — готовы. Сливаем через дуршлаг, не промываем, кладём сливочное масло.</p>
', 3),

(1, 'Секретный соус', 'demo', '
<h1>Соус, от которого пельмени перестают быть просто пельменями</h1>
<p>Майонез, кетчуп и кетчунез — скучно. Вот рецепт, который не раз спасал ужин и превращал скучные пельмени в небольшой домашний Мишлен.</p>
<p>Вам понадобится: три столовые ложки сметаны (любой, от 15% и выше), чайная ложка дижонской горчицы, половина чайной ложки соевого соуса, щепотка чёрного перца. По желанию — капля уксуса или лимонного сока для кислинки.</p>
<p>Смешиваем всё в чайной чашке. Вкус должен получиться сливочно-острым, с солёным привкусом. Если сметана густая — добавьте ложку воды, чтобы консистенция была как у соуса, а не как у крема.</p>
<p>Не рекомендуем готовить заранее: свежесмешанный соус вкуснее того, что простоял в холодильнике ночь.</p>
', 4),

(1, 'Пельмени с нуля', 'vip', '
<h1>Домашние пельмени: инструкция без иллюзий</h1>
<p>Предупреждаем: это длинный вечер, много му́ки́ на кухне и, возможно, обида на себя за то, что вообще это начал. Но по вкусу — другая планета. И морозилка потом месяц благодарит.</p>
<p><strong>Тесто.</strong> 500 грамм муки, 200 мл тёплой воды, одно яйцо, чайная ложка соли. Месить десять минут, пока не перестанет липнуть к рукам. Накрыть плёнкой и дать отдохнуть полчаса.</p>
<p><strong>Фарш.</strong> 500 грамм смеси свинины и говядины 50 на 50, одна средняя луковица через тёрку, зубчик чеснока, соль, перец, и — главный трюк — две столовые ложки ледяной воды. Вода делает фарш сочным, не пропускайте.</p>
<p>Раскатываем тесто тонко-тонко (прозрачно на свет), вырезаем кружки стаканом, кладём чайную ложку фарша, лепим. Первые десять штук будут кривыми. К тридцатому вы станете профи.</p>
<p>Готовые раскладываем на доске, присыпаем мукой, отправляем в морозилку на час. Потом ссыпаем в пакет. Варить — как в уроке про кипящую воду.</p>
', 5);

INSERT INTO lessons (course_id, title, type, content, sort_order) VALUES
(2, 'Анатомия утюга', 'free', '
<h1>Утюг изнутри: что, где и зачем</h1>
<p>Современный утюг выглядит сложнее, чем он есть. Пять кнопок и одно колесо, но на коробке обещают какую-нибудь технологию пара нового поколения. На деле важны только три части.</p>
<p><strong>Подошва.</strong> Металлическая пластина, которая касается ткани. Бывает стальная, тефлоновая, керамическая. Главное — чтобы на ней не было царапин и подгорелого налёта. Протирайте влажной тряпкой после каждой глажки.</p>
<p><strong>Регулятор температуры.</strong> Обычно колесо с символами точек или названиями тканей. Одна точка — минимум, три точки — максимум. Первое правило жизни: начинайте с минимума, прибавляйте если надо.</p>
<p><strong>Паровой удар.</strong> Большая кнопка сверху, которая выпускает облако пара. Помогает расправить складки, которые утюг не берёт напором. Резервуар для воды — внутри, наливать только фильтрованную, иначе накипь убьёт утюг за месяц. А лучше не фильтрованную, а прямо дистиллированную. В ней совсем нет минералов, которые осаждаются в виде накипи.</p>
', 1),

(2, 'Температура и ткани', 'free', '
<h1>Какую температуру ставить на какую ткань</h1>
<p>Производители утюгов давно договорились и ставят значки в виде точек. Запомните три уровня — и больше не надо гадать.</p>
<p><strong>Одна точка (110°C) — синтетика.</strong> Полиэстер, нейлон, акрил. Горячий утюг плавит такие ткани за секунды: сначала появится блестящий след, потом дырка. Если на бирке значок «не гладить» — <strong>не гладьте</strong>. Выглядит, как перечёркнутый утюг.</p>
<p><strong>Две точки (150°C) — шерсть, шёлк, вискоза.</strong> Гладить через влажную марлю или с изнанки. Шёлк вообще лучше обработать паром сверху, не касаясь подошвой.</p>
<p><strong>Три точки (200°C) — хлопок, лён.</strong> Любимые ткани утюга. Чем горячее — тем лучше разглаживаются. Лён вообще почти невозможно отутюжить без пара и высокой температуры.</p>
<p>Если на одной вещи смешанный состав — ориентируйтесь на самую нежную нитку. 30% шёлка в хлопковой рубашке означает режим для шёлка.</p>
', 2),

(2, 'Стрелки на брюках', 'demo', '
<h1>Стрелки, от которых штаны перестают быть пижамой</h1>
<p>Стрелка — тонкая вертикальная линия, которая делит штанину пополам. Придаёт брюкам вид серьёзности, а их владельцу — иллюзию собранности. Делается за пять минут.</p>
<p>Разложите брюки на доске так, чтобы швы по бокам штанины легли друг на друга ровно. Это самый важный шаг: кривые швы — кривая стрелка.</p>
<p>Увлажните место сгиба — распылителем или влажной марлей. Утюг с паром — идеально. Положите сверху марлю или тонкую хлопковую ткань, чтобы не осталось блеска от подошвы.</p>
<p>Прогладьте сгиб с нажимом, медленно, от колена вниз. Потом — от колена вверх до пояса. Линия должна стать острой, как лезвие. Переверните и повторите с другой штаниной. Готово.</p>
<p>Хитрость: свежевыглаженные стрелки держатся дольше, если дать брюкам полежать в разложенном виде пару минут перед тем, как надевать.</p>
', 3),

(2, 'Рубашка за 3 минуты', 'vip', '
<h1>Рубашка за 180 секунд</h1>
<p>Порядок глажки рубашки — не вопрос вкуса. Это алгоритм, который экономит время и избавляет от повторных проходов по уже выглаженным местам.</p>
<p><strong>1. Воротник.</strong> Сначала с изнанки — от углов к центру, иначе на концах останутся складки. Потом с лицевой стороны.</p>
<p><strong>2. Манжеты.</strong> По той же схеме: сначала изнанка, потом лицо. Расстегните пуговицы, чтобы гладить плоско.</p>
<p><strong>3. Плечи (кокетка).</strong> Наденьте плечо рубашки на узкий край доски, как носок на руку. Гладим спереди, потом сзади.</p>
<p><strong>4. Рукава.</strong> Распрямите рукав по шву, проведите утюгом от плеча к манжете. Переверните и повторите. Избегайте стрелок на рукавах — это признак плохого вкуса.</p>
<p><strong>5. Спинка и полочки.</strong> Самая крупная часть — на конец. Гладим длинными проходами. Вокруг пуговиц — аккуратно, носиком утюга.</p>
<p>Готовую рубашку сразу на вешалку. Если бросить на диван — пять минут, и все рукава в складках.</p>
', 4);

INSERT INTO lessons (course_id, title, type, content, sort_order) VALUES
(3, 'Символы на бирках', 'free', '
<h1>Значки на бирках: расшифровка</h1>
<p>Каждая вещь приходит с ярлыком, на который нанесены пиктограммы. Большинство людей их игнорирует и потом покупает новую вещь. Вам достаточно знать четыре вида значков.</p>
<p><strong>Тазик с водой — стирка.</strong> Цифра внутри означает максимальную температуру. Без цифры, но с одной точкой — холодная. С двумя — тёплая. Рука в тазу — только вручную. Перечёркнутый тазик — <strong>не стирать</strong>. Совсем.</p>
<p><strong>Треугольник — отбеливание.</strong> Пустой — можно любым отбеливателем. Две полоски внутри — только без хлора. Перечёркнутый — ни в коем случае не отбеливать.</p>
<p><strong>Квадрат — сушка.</strong> С кругом внутри — можно сушить в машине. Без круга — только на воздухе. Горизонтальная линия в квадрате — сушить плашмя, иначе вещь растянется.</p>
<p><strong>Утюг — глажка.</strong> Точки внутри — температура (как в курсе про глажку). Перечёркнутый — даже не пытайтесь.</p>
<p>Круг — химчистка, и это отдельная история. Если собираетесь стирать сами — просто не покупайте вещь с одним голым кругом на бирке.</p>
', 1),

(3, 'Сортировка белья', 'demo', '
<h1>Сортировка: как не покрасить футболки в розовый</h1>
<p>Если вы когда-нибудь видели розовую белую рубашку, которая раньше была белой, — значит, рядом в барабане лежал красный носок. Избежать этого помогает сортировка.</p>
<p><strong>По цвету — три кучи.</strong> Белое (белые футболки, носки, полотенца). Цветное светлое (бежевое, голубое, розовое). Тёмное и яркое (чёрное, синее, красное, коричневое). Стирать каждую кучу отдельно.</p>
<p><strong>По ткани — отдельно нежное.</strong> Шёлк, шерсть, кашемир, нижнее бельё, колготки — в сетчатый мешок для деликатной стирки. Джинсы и полотенца — никогда вместе с футболками: ворс и линька.</p>
<p><strong>По степени загрязнения.</strong> Сильно грязное — отдельно. Если кинуть рабочие джинсы с белой рубашкой, рубашка впитает грязь из воды.</p>
<p>Первая стирка новой цветной вещи — всегда отдельно. Особенно джинсов и чёрных футболок: они линяют первые 2–3 раза, и соседям в барабане будет невесело.</p>
', 2),

(3, 'Пятна: гид по выживанию', 'vip', '
<h1>Пятна: краткий справочник выводителя</h1>
<p>Главное правило борьбы с пятнами: действовать сразу. Свежее пятно выводится в два раза проще, чем высохшее. Если не можете сразу — хотя бы промокните и замочите в холодной воде.</p>
<p><strong>Кровь.</strong> Только холодная вода. Горячая заваривает белок, и пятно остаётся навсегда. Замочите на час, потом хозяйственное мыло — и в стирку.</p>
<p><strong>Жир.</strong> Средство для мытья посуды. Нанесите каплю прямо на пятно, разотрите пальцами, оставьте на 10 минут. Потом стирка как обычно. Работает и на одежде, и на скатертях.</p>
<p><strong>Красное вино.</strong> Сначала густо посыпьте солью — она втянет влагу. Потом залейте кипятком сверху, держа ткань натянутой. Пятно сходит волшебно.</p>
<p><strong>Кофе и чай.</strong> Холодная вода с каплей уксуса. Если ткань белая — можно перекись водорода точечно.</p>
<p><strong>Шариковая ручка.</strong> Спирт или спиртосодержащий гель для рук. Подложите полотенце под пятно, промокните сверху ватным диском со спиртом — чернила перейдут на полотенце.</p>
<p>Чего <strong>никогда</strong> не стоит делать: тереть пятно. Тереть — значит вбивать его глубже в волокна. Только промокать.</p>
', 3);

INSERT INTO lessons (course_id, title, type, content, sort_order) VALUES
(4, 'Что такое флаг', 'free', '
<h1>Что такое флаг</h1>
<p>В мире CTF и курса, который вы сейчас читаете, <strong>флаг</strong> — это короткая уникальная строка, которую нужно найти. По сути, цифровой трофей: «я сюда добрался, вот доказательство».</p>
<p>У нас все флаги выглядят одинаково: <code>alfa{текст_через_подчёркивания}</code>. Такой формат — маркер того, что перед вами именно флаг, а не случайная подозрительная строчка или фраза в коде.</p>
<p>Флаги прячут в местах, до которых сложно добраться — придётся хакать. Иногда в базе данных у пользователя, к которому у вас нет доступа. Иногда в шифрованных данных, от которых у вас нет ключа. Иногда в файле, который вообще не используется сервисом — нужно придумать, как заставить приложение выполнить произвольный код.</p>
<p>Этот курс — про то, как искать. Без спойлеров и подсказок про конкретные задачи. Только методология.</p>
', 1),

(4, 'Где водятся флаги', 'free', '
<h1>Где водятся флаги</h1>
<p>Фантазия авторов CTF-заданий богатая, но типовых сред обитания флагов не так много. В нормальном CTF место жительства флага не нужно угадывать — есть несколько логичных мест, привязанных к категории задания.</p>
<p><strong>Web.</strong> Флаг лежит в базе у админа, в файле <code>/flag.txt</code> на сервере, в переменной окружения или в ответе закрытой API-ручки. Способ поимки — SQL-инъекция, SSRF, IDOR, RCE, обход авторизации и т.д.</p>
<p><strong>Crypto.</strong> Флаг зашифрован, и вам выдают шифротекст вместе с уязвимой схемой шифрования или бажным алгоритмом. Ломаете шифр — получаете флаг.</p>
<p><strong>Reverse.</strong> Флаг зашит внутри бинарника, возможно, в зашифрованном виде. Нужно разобрать алгоритм программки и подобрать вход, который пройдёт все проверки до финального <code>printf</code> с выводом поздравления и флага.</p>
<p><strong>Pwn.</strong> Флаг — это файл на удалённом сервере рядом с уязвимым бинарём. Эксплойт даёт шелл, выполнение машинного кода или чтение произвольного файла, после чего вы просто читаете <code>flag.txt</code> и забираете очки.</p>
<p><strong>Forensics.</strong> Флаг — это улика в дампе памяти, pcap-файле, образе диска или внутри картинки. Инструменты известны: <code>Volatility</code>, <code>Wireshark</code>, <code>Binwalk</code> — разберите данный вам файл по байтам, и найдёте то, что ищете.</p>
<p>И самое главное: <strong>читайте условие задания</strong>. Из категории и формулировки обычно ясно, чего вам нужно достичь.</p>
', 2),

(4, 'Как ловят флаги', 'demo', '
<h1>Как ловят флаги: практический подход</h1>
<p>Охота на флаг — это не магия и не гениальные инсайты. Это методичное наблюдение, формулировка гипотезы и проверка её на практике. Три шага, которые работают на большинстве задач.</p>
<p><strong>Шаг 1. Картина системы.</strong> Какие роли есть? Какие действия с какими токенами? Как код решает, запретить или разрешить? Нарисуйте на бумаге прямоугольники со стрелочками — выглядит по-детски, но экономит часы размышлений в уме.</p>
<p><strong>Шаг 2. Поиск "странного".</strong> Посмотрите на каждую проверку: что будет, если сюда попадут не стандартные входные данные, а что-то хитроумное? Может, используется какая-то кастомная криптография? В общем, нужно набить руку, а точнее глаз, чтобы тот выцеплял из исходников подозрительные места.</p>
<p><strong>Шаг 3. Эксперимент.</strong> Сформулируйте гипотезу одним предложением: «если я сделаю X, то смогу заставить систему сделать Y». Проверьте. Если не сработало — поняли, почему, и сформулировали следующую. Если сработало — вы уже ближе.</p>
<p>Не бойтесь возвращаться назад. Большинство решений приходит не с первой попытки, а с третьей или четвёртой, а то и с тридцать четвёртой. Главное — не биться головой в одну стену, а пробовать новые подходы.</p>
', 3),

